#include<cstdio>
#include<algorithm>
#include<vector>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;int a[N],P[N],p,n,Q;LL wl[N],wr[N];
inline int bnd(int k){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline void add(int x){while(x<=p)++P[x],x+=(x&-x);}
inline int qry(int x){int res=0;while(x)res+=P[x],x^=(x&-x);return res;}
struct Pr{int l,r,idx;}q[N];std::vector<Pr> Qr[N],Ql[N];LL ansr[N],ansl[N],ans[N];

const int BK=675;int blk,ql[N/BK+10],loc[N],cc[N/BK+10],c[N];
inline void Init(){rep(1,n,i)loc[i]=(i-1)/BK+1;blk=loc[n];rep(1,blk,i)ql[i]=(i-1)*BK+1;}
inline void Add(int x){rep(1,loc[x],B)++cc[B];rep(ql[loc[x]],x,i)++c[i];}
inline int Qry(int l,int r){return cc[loc[l]+1]+c[l]-cc[loc[r+1]+1]-c[r+1];}

int main()
{
	
	n=read();Q=read();rep(1,n,i)P[i]=a[i]=read();Init();
	std::sort(P+1,P+n+1);p=std::unique(P+1,P+n+1)-P-1;rep(1,n,i)a[i]=bnd(a[i]);
	memset(P,0,(p+2)*sizeof(P[0]));rep(1,n,i){add(a[i]);wr[i]=wr[i-1]+(i-qry(a[i]));}
	memset(P,0,(p+2)*sizeof(P[0]));drep(n,1,i){wl[i]=wl[i+1]+qry(a[i]-1);add(a[i]);}
	rep(1,Q,i)q[i].l=read(),q[i].r=read(),q[i].idx=i;
	std::sort(q+1,q+Q+1,[&](const Pr&x,const Pr&y){return loc[x.l]==loc[y.l]?(loc[x.l]&1?x.r<y.r:x.r>y.r):x.l<y.l;});
	int l=1,r=0;rep(1,Q,i)
	{
		if(r<q[i].r)Qr[l-1].push_back({r+1,q[i].r,i});if(r>q[i].r)Qr[l-1].push_back({q[i].r+1,r,i});r=q[i].r;
		if(l<q[i].l)Ql[r+1].push_back({l,q[i].l-1,i});if(l>q[i].l)Ql[r+1].push_back({q[i].l,l-1,i});l=q[i].l;
	}
	rep(0,n-1,i){for(Pr v:Qr[i]){rep(v.l,v.r,j)ansr[v.idx]+=Qry(a[j]+1,p);}Add(a[i+1]);} 
	memset(c,0,(n+2)*sizeof(c[0]));memset(cc,0,(blk+2)*sizeof(cc[0]));
	drep(n+1,2,i){for(Pr v:Ql[i])rep(v.l,v.r,j)ansl[v.idx]+=Qry(1,a[j]-1);Add(a[i-1]);}
	LL Ans=0;l=1;r=0;rep(1,Q,i)
	{
		if(r<q[i].r)Ans+=wr[q[i].r]-wr[r]-ansr[i];if(r>q[i].r) Ans-=wr[r]-wr[q[i].r]-ansr[i];r=q[i].r;
		if(l<q[i].l)Ans-=wl[l]-wl[q[i].l]-ansl[i];if(l>q[i].l) Ans+=wl[q[i].l]-wl[l]-ansl[i];l=q[i].l;
		ans[q[i].idx]=Ans;
	}
	rep(1,Q,i)printf("%lld\n",ans[i]);return 0;
}
